class Solution(object):
    def hardestWorker(self, n, logs):
        max_time = logs[0][1]
        result = logs[0][0]
        for i in range(1, len(logs)):
            task_time = logs[i][1] - logs[i-1][1]
            if task_time > max_time:
                max_time = task_time
                result = logs[i][0]
            elif task_time == max_time:
                result = min(result, logs[i][0])
        return result
